                    ?? throw new InvalidOperationException("Auth succeeded but token was null.");

                var expiresAt = DateTimeOffset.UtcNow.AddSeconds(config.TokenValiditySeconds - 30);

                tokenProvider = async () =>
                {
                    if (DateTimeOffset.UtcNow < expiresAt)
                        return cachedToken;

                    expiresAt = DateTimeOffset.UtcNow.AddSeconds(config.TokenValiditySeconds);

                    var refreshed = await authApi.GetFullAccessTokenAsync(tokenRequest);
                    cachedToken = refreshed.VarToken
                        ?? throw new InvalidOperationException("Token refresh returned null.");
